mapper.select:
SELECT B_ID, B_CATEGORY, B_CC, B_TITLE, B_CONTENT, B_CREATED_ID, B_CREATED_DATE, B_UPDATED_ID, B_UPDATED_DATE, B_VIEWS FROM BOARD WHERE
B_ID = #{keyword}
B_CATEGORY = #{keyword}
B_CC = #{keyword}
LOWER(${column}) LIKE LOWER('%'||#{keyword}||'%')
ORDER BY B_CREATED_DATE DESC

mapper.update:
UPDATE BOARD
SET B_VIEWS = B_VIEWS + 1
WHERE B_ID = #{id}
